const total = $('Identify Unproccessed Artifacts').all().length;
const iteration = ($runIndex + 1) * 100;
const runId = $('Create Run Id').first().json.run_id;

// Current % and previous %
const currentPercent = (iteration / total) * 100;
const prevPercent = ((iteration - 100) / total) * 100; // because IF node steps by 100

// Check if we crossed a 10% boundary
if (
  Math.floor(currentPercent / 10) > Math.floor(prevPercent / 10)
  || iteration >= total 
) {
  return [{
    json: {
      run_id: runId,
      progress_count: iteration,
      progress_percent: Math.floor(currentPercent)
    }
  }];
}

return [];
